use quote::{quote, quote_spanned};
use syn::{parse_quote, ItemStruct, Type};

fn build_my_struct(args: parse_quote!(MyCustomType)) -> ItemStruct {
    let name = args.to_string();
    let fields = if args.fields.is_empty() {
        vec![]
    } else {
        // Convert each field to a literal struct field
        let mut fields = Vec::new();
        for f in args.fields.iter() {
            let ty = match f.ty.parse::<Type>() {
                Ok(t) => t,
                Err(_) => return ItemStruct { 
                    attrs: Vec::new(), 
                    generics: args.generics,
                    fields: None, // Will be filled later
                },
            };
            let lit = quote_spanned!(f.span() => #f);
            fields.push(syn::Expr::Lit(lit));
        }
        fields
    };

    ItemStruct {
        attrs: Vec::new(),
        generics: args.generics,
        fields,
    }
}
